/// Paragraph: 1000-LOAD-RECORD
fn v2_p_1000_load_record(record: &mut CobolRecord, _files: &mut std::collections::HashMap<String, CobolFile>) {
    record.fill_field("TSPFL-RECORD", 0x20);
    cobol_move(record, &format!("DATA-CUST-NUM({})", record.get_i64("SUB")), "CM-CUST-NUM");
    cobol_move(record, "CM-CUST-NUM", "TSPFL-KEY");
    cobol_move(record, &format!("DATA-COMPANY({})", record.get_i64("SUB")), "CM-COMPANY");
    cobol_move(record, &format!("DATA-ADDRESS-1({})", record.get_i64("SUB")), "CM-ADDRESS-1");
    cobol_move(record, &format!("DATA-ADDRESS-2({})", record.get_i64("SUB")), "CM-ADDRESS-2");
    cobol_move(record, &format!("DATA-ADDRESS-3({})", record.get_i64("SUB")), "CM-ADDRESS-3");
    cobol_move(record, &format!("DATA-TELEPHONE({})", record.get_i64("SUB")), "CM-TELEPHONE");
    cobol_move(record, &format!("DATA-DP-MGR({})", record.get_i64("SUB")), "CM-DP-MGR");
    cobol_move(record, &format!("DATA-MACHINE({})", record.get_i64("SUB")), "CM-MACHINE");
    cobol_move(record, &format!("DATA-NO-TERMINALS({})", record.get_i64("SUB")), "CM-NO-TERMINALS");
    if (record.get_i64("SUB") == 1 || record.get_i64("SUB") == 3 || record.get_i64("SUB") == 5 || record.get_i64("SUB") == 7 || record.get_i64("SUB") == 9 || record.get_i64("SUB") == 10 || record.get_i64("SUB") == 11) {
    record.set_bytes("CM-DISK", b"8417");
    record.set_bytes("CM-TAPE", b"1600 BPI");
    record.set_bytes("CM-MEMORY", b"1MEG");
    } else {
    record.set_bytes("CM-DISK", b"8470");
    record.set_bytes("CM-TAPE", b"6250 BPI");
    record.set_bytes("CM-MEMORY", b"3MEG");
    }
    if (record.get_i64("SUB") == 4 || record.get_i64("SUB") == 5 || record.get_i64("SUB") == 8 || record.get_i64("SUB") == 12 || record.get_i64("SUB") == 14) {
    record.fill_field_pattern("CM-DISK", b"*");
    record.fill_field_pattern("CM-TAPE", b"*");
    }
    {
    let _data = record.get_raw_bytes("TSPFL-RECORD");
    if let Some(fh) = _files.get_mut("TSPFILE") {
        match fh.indexed_write(&_data) {
            Ok(()) => { { let _fs_str = format!("{:0>2}", FileStatus::Success); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } }
            Err(_fs) => { { let _fs_str = format!("{:0>2}", _fs); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } }
        }
    } else { let _fs = FileStatus::WriteNotAllowed; { let _fs_str = format!("{:0>2}", _fs); record.set_bytes("CUST-STAT", _fs_str.as_bytes()); } }
    }
    if ({ let _l = record.get_display("CUST-STAT"); let _r = "00".to_string(); let _w = _l.len().max(_r.len()); format!("{:<w$}", _l, w = _w) != format!("{:<w$}", _r, w = _w) } && { let _l = record.get_display("CUST-STAT"); let _r = "02".to_string(); let _w = _l.len().max(_r.len()); format!("{:<w$}", _l, w = _w) != format!("{:<w$}", _r, w = _w) }) {
    { println!("{}{}{}{}", "WRITE: ".to_string(), record.get_display("TSPFL-KEY"), ", Status: ".to_string(), record.get_display("CUST-STAT")); use std::io::Write; std::io::stdout().flush().ok(); }
    }
}

